      case Token.IN:
      case Token.INSTANCEOF:
      // Inversion
      case Token.NOT:
      // Logical operations
      case Token.AND:
      case Token.OR:
      // Conditional (ternary)
      case Token.HOOK:
      // Delete operator returns a boolean.
      case Token.DELPROP:
        return true;
      // Assignment might be a Boolean if assigned value is Boolean
      case Token.ASSIGN:
